const Q_ECONOMICS_1999=[{"id": "objective>Economics>1999>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a firm, three employees earn #5,500 each, four earn #3,300 each, two earn #5,000 each and one earns #7,000. the mean income of the employees is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#5200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#4760</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#4670</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#2080</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the mean income of the employees, we need to sum up all the incomes and divide by the total number of employees.  <br/> The total income is (3 x5500) + (4 x 3300) + (2x 5000) + ( 1 x 7000)  <br/> = 46700. <br/>  <br/>  The total numbe9r of employees is 3+4+2+1 = 10.  <br/>  <br/> Therefore, the mean income is 46700/10 <br/>  = 4670</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>1999>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Abubakar has the choice of buying either a house or a mercedes benz car for #1.5m plus #0.5m running cost. if he decides to buy the mercedes benz car, his opportunity cost is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#1.5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#2.0m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the house</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the car</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity cost is the want left unbought in order to get more pressing need. To Abubakar, his opportunity cost is the house he did not buy.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : OPPORTUNITY COST"}, {"id": "objective>Economics>1999>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of a production possibility frontier is determined by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing the relative costs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diminishing returns to a fixed factor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing returns to a variable factor</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the PPC depends on whether there are increasing, decreasing or constant costs. The shape of the PPC is a concave to the origin to represent increasing opportunity cost with increased output of a good. <br/>  <br/> This is because the shape of the production possibility curve is typically concave due to the principle of increasing opportunity costs. As more resources are allocated to produce one good, increasingly larger amounts of the other must be sacrified. This result in a bowed-out shape of the PPC, reflecting increasing relative costs.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCTION FUNCTIONS & LAWS OF RETURNS"}, {"id": "objective>Economics>1999>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Normative economics deals with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">what is and not what should be</div>", "<div style=\"font-family:Cambria;font-size:17px;\">facts and not figures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">facts and figures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">value judgements</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Normative economics focuses on value-based judgments aimed at improving economic development, investment projects, and the distribution of wealth.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>1999>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The determinants of elasticity include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price, time and availability of alternatives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technology and cost of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">time and availability of alternatives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price, time and technology changes.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There are many factors on which elasticity of demand depends on, they are: <br/> - variety of uses to which an article can be put <br/> - price range of the product <br/> - the time or factors <br/> - percentage amount of the income spent on an article <br/> - availability of substitutes</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1999>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> period 1</td><td style=\"border:1px solid black;text-align:center;\"> period 2</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">family income</td><td style=\"border:1px solid black;text-align:center;\"> #1000</td><td style=\"border:1px solid black;text-align:center;\"> #1500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">expenditure on clothing</td><td style=\"border:1px solid black;text-align:center;\"> #100</td><td style=\"border:1px solid black;text-align:center;\"> #200</td></tr></table></div> <br/> In the table above, the income elasticity of clothing is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">e = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">∆Q</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">∆Y</span>   x <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">Y</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">Q</span> <br/>  <br/> where ∆Q = Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> ∆Y = Y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - Y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> Y = 1st price <br/> Q = 1st quantity <br/>  <br/>  e = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">200 -100 </span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 1500 - 1000</span>  x <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">100</span>  <br/>  <br/> e = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">100</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">500</span>  x <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">100</span> <br/>  <br/> e = 2</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1999>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A capitalist economy is one characterized by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">private ownership of factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ownership of factors of production by rich members of the society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of capital and labour in fixed proportions during production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of capital intensive methods of production.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capitalist economy system is also called free market economy and it is an economy system in which the means of production is controlled by a private individual.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>1999>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a planned economy, what shall be produced is determined primarily by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">what the consumer wants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government decisions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price mechanism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the pattern of consumer spending </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A planned economy system is also called socialist economy system. It is an economy system in which the means of production are controlled by the state/government.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>1999>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer questions below <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> are initial demand and supply curves with equilibrium a E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>. Other supply and demand curves with equlibra points are indicated. <br/>  <br/> Points E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> and E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> are respectively equilibra points for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>; D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>; D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>; D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>; D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> is the equilibrium point for D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> while E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> is the equilibrium point for D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> curve respectively.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>1999>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer questions below <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> are initial demand and supply curves with equilibrium a E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>. Other supply and demand curves with equlibra points are indicated. <br/> identify the three important factors that can make S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> to become either S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> or S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">technology, weather and population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technology, price and tastes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weather, price and technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population, weather and tastes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factors such as price of the commodity, price of other commodity, cost of production, technology, goals of producers, government policies, weather, taxation will shift the supply curve to the right or to the left i.e S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> to become either S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> or S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "topic": "THE THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1999>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Commodity X   <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> Commodity Y <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The graph above illustrate  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">joint demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">derived demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">composite demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competitive demand</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Competitve demand is also known as substituted demand. These are alternative commodities which can satisfy similar wants. A decrease in demand for one will lead to an increase in demand for the other and vice versa. From the diagram above, the diagram for commodity x increases while the diagram for commodity Y falls indicating that the two goods are subtituted goods.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>1999>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above the consumer at point </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">G</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rule for consumer equilibrium using a budget line and an indifference curve is that a consumer is in equilibrium when the slope of the budget line is tangential to the indifference curve.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>1999>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A utility maximizing household will allocate its expenditure so that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">more naira is spent on commodities with the highest utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less naira is spent on commodities with the lowest utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the utility of the last naira spent on each commodity is equal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the amount spent on each commodity is equal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If he finds that the marginal utility of good A is higher than that of good B, he will substitute A for the B till their marginal utilities are equalized ( the same) and if the last naira spent on a good A gives him less marginal utility, he will withdraw the amount from A and spend it on good B.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>1999>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The downward sloping part of the long-run average cost curve of a firm may be attributable to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diminishing returns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the law of variable proportions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diseconomies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing returns to scale</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the LRAC curve consist of a series of SRAC. However, the LRAC is a flatter u-shaped than the SRAC due to law of returns to scale.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>1999>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main function of price in the economic system is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">allocate scarce resources among competing uses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure equitable distribution of income and wealth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine the demand for and the supply of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remove all the constraints on production of goods and services.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The functions/merit of the price system is that it determines how scarce goods and services are allocated, it indicates changes in demand or wants of consumers etc.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE"}, {"id": "objective>Economics>1999>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">S/No</td><td style=\"border:1px solid black;text-align:center;\"> Sector</td><td style=\"border:1px solid black;text-align:center;\"> No. of people</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">I.</td><td style=\"border:1px solid black;text-align:center;\"> Agriculture forestry and fishing</td><td style=\"border:1px solid black;text-align:center;\"> 10 050 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">II.</td><td style=\"border:1px solid black;text-align:center;\"> Mining and quarrying</td><td style=\"border:1px solid black;text-align:center;\"> 1 500 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">III.</td><td style=\"border:1px solid black;text-align:center;\"> Transport and communication</td><td style=\"border:1px solid black;text-align:center;\"> 2 000 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">IV.</td><td style=\"border:1px solid black;text-align:center;\"> Manufacturing</td><td style=\"border:1px solid black;text-align:center;\"> 1 750 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">V.</td><td style=\"border:1px solid black;text-align:center;\"> Basic construction</td><td style=\"border:1px solid black;text-align:center;\"> 750 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">VI.</td><td style=\"border:1px solid black;text-align:center;\"> Distributive Trade</td><td style=\"border:1px solid black;text-align:center;\"> 3 000 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">VII.</td><td style=\"border:1px solid black;text-align:center;\"> Administration</td><td style=\"border:1px solid black;text-align:center;\"> 1 250 000</td></tr></table></div> <br/> calculate the total number of people engaged in tertiary production from the data above</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5 000 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6 250 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11 750 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 250 000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tertiary production involves the provision of services. From the table above, the number of people engaged are: <br/> = 2,000,000 + 3,000,000 + 1,250,000 <br/> = 6, 250,000</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>1999>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the characteristics of an imperfect market is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">large numbers of buyers and sellers in the market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">awareness of market conditions by buyers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of substitutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heterogeneity of products</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristics or features of imperfect market are: <br/> - the goods are not homogenous i.e it is heterogenous <br/> - there is no free entry and exit <br/> - the are few buyers and sellers <br/> - there is no perfect knowledge about the market <br/> - there is preferential treatement</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>1999>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic of the average fixed cost is that, it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rises and falls faster than the marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is U-shaped and intersects the price axis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is always higher than the average variable cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">falls continuously but is never equal to zero</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Average Fixed Cost (AFC) is the fixed cost of production divided by the quantity of output produced. Since fixed costs do not change with the level of output, AFC decreases as output increases. Therefore, it falls continuously but is never equal to zero because fixed costs are always present, regardless of the level of output.</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM"}, {"id": "objective>Economics>1999>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In perfect competition, every firm is a price</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">giver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bidder</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A perfect competitive market is a price taker and quantity adjuster i.e the forces of demand and supply determines the price in the market.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>1999>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that the total fixed cost is #1000, total variable cost #2500 and the output, 100 units. find the average total cost of producing one unit </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#45</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#35</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#30</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ATC = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">TC </span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">Q</span> <br/>  <br/> Note that TC = FC + VC <br/>  TC = 1000 + 2500 <br/> = 3,500 <br/>  <br/> Therefore, ATC = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">3500</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">100</span> <br/>  <br/> = #35</div>", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT"}, {"id": "objective>Economics>1999>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following falls continuously as output expands?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average fixed cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average variable cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average fixed cost (AFC) is the total fixed cost divided by the quantity of output produced. As output increases, AFC decreases because the same amount of fixed costs is spread over a larger number of units of output. This is known as spreading overhead. The other costs (marginal cost, average variable cost, and average cost) do not necessarily fall continuously as output expands.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>1999>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major obstacle to rapid agricultural development in Nigeria is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ineffective use of crude implements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inability of farmers to adopt modern technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">introduction of the green revolution programme</div>", "<div style=\"font-family:Cambria;font-size:17px;\">declining population growth rate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The use of simple farm tools like cutlass, hoe etc leads to low agricultural production. Majority of the farmers are so poor that they cannot afford to buy modern tools and equipment to improve their product.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>1999>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The land tenure system in Nigeria impedes agricultural production because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">land fragmentation makes possible easy access to land ownership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it discourages specialization of factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it limits opportunity for mass production of agricultural goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">small land holders generally do not get enough fertilizer to use</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The type of land tenure system in Nigeria discourages farmers from acquiring land for large scale farming.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>1999>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major problem of cooperative societies in Nigeria is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they often lack cohesion and continuity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their liability is unlimited to members </div>", "<div style=\"font-family:Cambria;font-size:17px;\">voting is by proxy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">their management style is poor</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cooperative societies in Nigeria often face the problem of lack of cohesion and continuity. This is because they are formed by a group of people who come together voluntarily to meet their common economic, social, and cultural needs and aspirations through a jointly-owned and democratically-controlled enterprise. The members may have different personal interests and goals, which can lead to conflicts and disagreements, thereby affecting the cohesion and continuity of the society.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>1999>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary objective of establishing the export processing zone is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">facilitate agricultural production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage the production and processing of export commodities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">erects structures that will facilitate the processing of imported raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">erect economic structures near the port</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The objective of establishing the export processing zone is to encourage the production and processing of export commodities.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>1999>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first petroleum exploring company to discover crude petroleum in Nigeria was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mobil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">texaco</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agip</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shell-BP</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first petroleum exploring company to discover crude petroleum in Nigeria was Shell British Petroleum in 1956.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>1999>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Concentrating industries in one place is advantageous because there are gains in terms of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">external economies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">internal economies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economies of scale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost economies</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">External economies arises from localization of industry. It is benefits a firm derives from the concentration or localization of industries in a particular area.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>1999>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution industralization refers to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the concentration of economics for even development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">setting up of industries for regional development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a situation in whcih local industries are set up to produce goods formerly imported</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the banning of import which are substitutes for domestically produced goods</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution strategy involves delibrate attempt by government aimed at encouraging the growth of industries within the country which produce goods and services which would otherwise have been imported.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION"}, {"id": "objective>Economics>1999>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An entrepreneur will continue to employ labour up to a point where </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cost are minimized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum efficiency is attained</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wages are equal to marginal product of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal product of labour is equal to zero</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economic theory,a  firm will hire workers up to the point where the additional cost of hiring one more worker (the wage) equals the additional revenue generated by the worker (the marginal product of labour). This ensures that the firm is maximizing its profit.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>1999>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Optimum population is defined as the level of population at which </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">per capita output is maximized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population is neither increasing nor decreasing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total national income is maximized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal efficiency of population is maximized </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word optimum means best. The optimum population is the ideal population which combined with other resources or means of production of the country will yield the maximum returns or income per head.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>1999>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a worker earns more than the wage just sufficient to keep him in his job, the excess income is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an economic rent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transfer earnings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">surplus value</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic rent is the extra income a worker receives above the minimum level they need in order to work</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : WAGES"}, {"id": "objective>Economics>1999>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">No.</td><td style=\"border:1px solid black;text-align:center;\"> items</td><td style=\"border:1px solid black;text-align:center;\"> Amount (#m)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\"> wages</td><td style=\"border:1px solid black;text-align:center;\"> 9000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\"> salaries</td><td style=\"border:1px solid black;text-align:center;\"> 7000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\"> government pensions</td><td style=\"border:1px solid black;text-align:center;\"> 1500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\"> unemployment pay and other social benefits</td><td style=\"border:1px solid black;text-align:center;\"> 1000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\"> rent and interest</td><td style=\"border:1px solid black;text-align:center;\"> 1500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\"> profits</td><td style=\"border:1px solid black;text-align:center;\"> 1500</td></tr></table></div> <br/> from the table above, calculate the national income</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#18,500m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#19,000m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#19,500m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#20,500m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using the income approach i.e adding the reward of the factors of production equals the national income excluding transfer payment such as unemployment benefit, gift, award,  pension , bursary etc. <br/>  <br/> Therefore, national income = 9,000 + 7,000 + 1,500 + 1,500 <br/> = #19,000million</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>1999>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">National income at factor cost means national income at </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">current prices </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nominal prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">last year prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">base year prices</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">National income at factor cost refers to the total income earned by the factors of production (i.e., land, labor, capital, and entrepreneurship) from the production of goods and services. This is calculated at base year prices to eliminate the effect of inflation and give a real value of the national income. Therefore, the correct answer is 'base year prices'.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>1999>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The value of the multiplier depends on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MPC and level of income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of personal income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of personal savings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government policy and MPC</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The value of the multiplier (k) depends on the MPC ( marginal propensity to consume) and the MPS ( marginal propensity to save). The higher the MPC, the higher the multiplier (k)</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>1999>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major problems of product distribution in most developing countries is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lack of storage facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large number of middlemen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate manpower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate means of transportation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major problems of product distribution in most developing countries is the large number of middlemen. Middlemen are intermediaries between producers and consumers in the distribution chain. They buy products from producers and sell them to consumers. While they provide a valuable service by making products available to consumers, they also increase the cost of products because each middleman adds his own profit margin to the price of the product. In developing countries, where there are often many middlemen, this can significantly increase the price of products and make them unaffordable for many consumers.</div>", "topic": "DISTRIBUTIVE TRADE : INTRODUCTION"}, {"id": "objective>Economics>1999>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Non-bank financial intermediaries do not </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provide credit facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accept deposits </div>", "<div style=\"font-family:Cambria;font-size:17px;\">accept demand deposits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sell shares</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Non bank financial institution is a financial institution that does not have full banking license and cannot accept deposits from the public.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>1999>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Inflation which is caused mainly by increases in the prices of factors of production is described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cost push inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand pull inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crawling inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spiral inflation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost push inflation occur when the cost of production is high. It also occur when there is an increase in the raw materials to produce goods and services.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>1999>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The relationship between the value of money and the price level is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">direct </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unpredictable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diverse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inverse</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is an inverse relationship between the value of money and the price level because when the price level rises, the value of money decreases and vice versa.</div>", "topic": "MONEY : VALUE OF MONEY"}, {"id": "objective>Economics>1999>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">People hold money for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">charity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stake keeping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit making </div>", "<div style=\"font-family:Cambria;font-size:17px;\">speculative purposes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to keynes, people hold for three reasons ( motives) which are: Speculative, Transactionary and Precautionary motive.</div>", "topic": "MONEY : DEMAND FOR MONEY"}, {"id": "objective>Economics>1999>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bills of exchange originate from a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">central bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">community bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development bank</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bills of exchange are drawn by individuals or banks and are generally transfereable by endorsements. It is originated from the comemercial bank.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>1999>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If high unemployment goes hand in hand with rising prices, the situation created is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hyperinflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stagflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moderate inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">galloping inflation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stagflation is a situation where a country experiences both stagnation and inflation or stagnation with inflation</div>", "topic": "INFLATION & DEFLATION : TYPES"}, {"id": "objective>Economics>1999>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the functions of money is that it helps </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">detect frauds in matters of exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">postpone payments without loss of count</div>", "<div style=\"font-family:Cambria;font-size:17px;\">store information about the intrinsic benefits of an item </div>", "<div style=\"font-family:Cambria;font-size:17px;\">record information about the valuation of an item</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the functions of money is that it serves as a standard of deferred payment. This means that it helps to postpone payments without loss of count. Money is an accepted means of payment for goods and services and repayment of debts in a particular country or socio-economic context.</div>", "topic": "MONEY : FUNCTIONS OF MONEY"}, {"id": "objective>Economics>1999>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy involves changes in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">open markets operations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revenue and expenditure of government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">money supply to the economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">imports and exports</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy involves changes in the overall government sending ( expenditure) in the overall level of taxation and the budgetary position.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>1999>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economic development may be defined as economic growth </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in a given country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over a long period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">and improved health facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">and improved distribution of wealth</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic development is defined as a sustained improvement in material well being of society. Apart from national income, it includes changes in socio, cultural, political as well as economic which contribute to material progress.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>1999>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The price of a good will not be affected by the imposition of a sales tax on it if the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supply is inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand is inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply is perfectly elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand is perfectly elastic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The price of a good will not be affected by the imposition of a sales tax on it if the supply is perfectly elastic. Elasticity in economics is a measure of a variable's sensitivity to a change in another variable. In this case, if supply is perfectly elastic, it means that suppliers are willing and able to produce and sell any amount of the good at a certain price. Therefore, even if a sales tax is imposed, suppliers can still supply the same amount of the good at the same price, absorbing the tax themselves. The other options are incorrect because if supply or demand is inelastic, the price will change with the imposition of a sales tax.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>1999>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A free trade area emerges when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">traders from one part of the country can move freely to other parts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">customs regulations are harmonized among countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a group of countries decide to remove restrictions on imports from one another </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the UNCTAD is in force</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A free trade agreement is a pact between two or more nations to reduce barriers to imports and exports among them. Under a free trade policy. good and services can be bought and sold across international borders with little or no government tariffs, quotas, subsidies, or prohibitions to inhibit their exchange.</div>", "topic": "INTERNATIONAL TRADE : ECONOMIC INTEGRATION IN AFRICA"}, {"id": "objective>Economics>1999>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Devaluation helps in checking adverse balance of payments if the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand for imports is elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand for imports is inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply of exports is elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand for experts is inelastic</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Devaluation is employed to eliminate persistent balance of payments deficits.A downward shift in the value of a nation's currency makes it more expensive for its citizen to buy imports and increases the competitiveness of their exports, thus helping to correct a deficit in the balance of payments.</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>1999>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Gains from trade depends on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">comparative advantage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absolute advantage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distributive cost advantage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">absolute cost advantage <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gains from international trade depends upon the cost ratios of differences in comparative cost advantage ratios in the two trading countries. The smaller the difference between exchange rate and cost of production the smaller the gains from trade and vice versa.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>1999>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Favourable terms of trade is important to a country because it facilities</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economic prosperity for importers and exporters </div>", "<div style=\"font-family:Cambria;font-size:17px;\">export of hard currency by the government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic prosperity for the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">import of hard currency by the government</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Favourable terms of trade is beneficial because the country needs fewer exports to buy a given number of imports. It might also have a positive impact on domestic cost push inflation when the terms of trade increases because the increase is indicative of falling import prices to export prices</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>1999>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most acceptable economic measure for trade protection is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">improve standards of living </div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect infant industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">safeguard strategic industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote foreign trade</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Protectionism refers to government policies that restrict international trade to help domestic industries. The trade protection is the delibrate attempt to limit imports or promote exports by putting up barriers to trade.</div>", "topic": "INTERNATIONAL TRADE : ECONOMIC INTEGRATION IN AFRICA"}];
